#include<bits/stdc++.h>
using namespace std;
int d,n,m,a[50005],ans;
bool pan(int x){
    int now=0,cnt=0;
    for(int i=1;i<=n+1;i++){
        if(a[i]-a[now]<x){
            cnt++;
        }else{
            now=i;
        }
    }
    return (cnt<=m);
}
int main(){
    cin>>d>>n>>m;
    for(int i=1;i<=n;i++) cin>>a[i];
    a[n+1]=d;
    int l=0,r=d;
    while(l<=r){
        int mid=(l+r)/2;
        if(pan(mid)){
            ans=mid;
            l=mid+1;
        }else{
            r=mid-1;
        }
    }
    cout<<ans;
}
